var series = transformedData.map(function(s) {
  return {
    type: 'custom',
    coordinateSystem: undefined,
    renderItem: function(params, api) {
      return {
        type: 'circle',
        shape: { cx: s.x, cy: s.y, r: s.r },
        style: {
          fill: ['rgba(84,112,198,0.35)', 'rgba(145,204,117,0.35)', 'rgba(250,200,88,0.35)'][params.seriesIndex % 3],
          stroke: ['#5470c6', '#91cc75', '#fac858'][params.seriesIndex % 3],
          lineWidth: 2
        },
        textContent: { style: { text: s.name + ' (' + s.size + ')', fill: '#333', font: '14px sans-serif' } },
        textConfig: { position: 'inside' }
      };
    },
    data: [0]
  };
});
option = {
  title: { text: 'User Segments (Euler/Venn)', left: 'center' },
  tooltip: {},
  series: series
};
